    -- Função de decodificação em memória
    local function _decode(data)
        -- Remover caracteres invisíveis
        data = data:gsub('[\200\x0B-\x0C\x0E-\x1F\x7F\x80-\x9F\u200B-\u200F\u2028-\u202F\u205F-\u206F\uFEFF]', '')
        
        -- Separar chunks
        local chunks = {}
        for chunk in data:gmatch('[^⫘]+') do
            table.insert(chunks, chunk)
        end
        
        -- Reordenar chunks
        local orderedChunks = {}
        for _, chunk in ipairs(chunks) do
            local marker = chunk:match('⦃([^⦄]+)⦄')
            if marker then
                local position = tonumber(marker, 36)
                local content = chunk:gsub('⦃[^⦄]+⦄', '')
                orderedChunks[position + 1] = content
            end
        end
        
        -- Reconstruir string
        local reconstructed = ''
        for i = #orderedChunks, 1, -1 do
            if orderedChunks[i] then
                reconstructed = reconstructed .. orderedChunks[i]
            end
        end
        
        -- Remover ruído matemático
        reconstructed = reconstructed:gsub('[∫∮∯∰∱∲∳∴∵∶∷∸∹∺∻∼∽∾∿≀≁≂≃≄≅≆≇≈≉≊≋≌≍≎≏]', '')
        
        return reconstructed
    end
    
