    -- Executar com ambiente isolado
    local function _safeExecute(code)
        local env = {}
        setmetatable(env, {__index = getfenv()})
        local func, err = loadstring(code)
        if func then
            setfenv(func, env)
            local success, result = pcall(func)
            if not success then
                -- Falha silenciosa
                return false
            end
            return true
        end
        return false
    end
    
    _safeExecute(decoded)
    
    -- Limpeza de memória
    scriptCodificado = nil
    decoded = nil
    _decode = nil
    _safeExecute = nil
